/* CSS Custom Properties */
:root {
  --bg: #0a0a0a;
  --bg-2: #1a1a1a;
  --bg-3: #2a2a2a;
  --neon: #39FF14;
  --neon-dim: #2db310;
  --neon-bright: #4fff28;
  --ink: #ffffff;
  --ink-muted: #cccccc;
  --ink-dim: #999999;
  --muted: #4a4a4a;
  --ring: #333333;
  --glow-strength: 0.5;
  --cyan: #00d4ff;
  --purple: #8b5cf6;
  --danger: #ff4444;

  /* Typography */
  --font-primary: 'Inter', system-ui, -apple-system, sans-serif;
  --font-heading: 'Orbitron', monospace;

  /* Spacing */
  --space-xs: 0.25rem;
  --space-sm: 0.5rem;
  --space-md: 1rem;
  --space-lg: 1.5rem;
  --space-xl: 2rem;
  --space-2xl: 3rem;
  --space-3xl: 4rem;

  /* Border radius */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;

  /* Transitions */
  --transition-fast: 150ms ease-out;
  --transition-normal: 250ms ease-out;
  --transition-slow: 400ms ease-out;

  /* Shadows */
  --shadow-glow: 0 0 20px rgba(57, 255, 20, 0.3);
  --shadow-card: 0 4px 20px rgba(0, 0, 0, 0.3);
  --shadow-lifted: 0 8px 40px rgba(0, 0, 0, 0.4);
}

/* Reset and Base Styles */
*,
*::before,
*::after {
  box-sizing: border-box;
}

* {
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-primary);
  background-color: var(--bg);
  color: var(--ink);
  line-height: 1.6;
  font-size: 16px;
  overflow-x: hidden;
  position: relative;
  min-height: 100vh;
}

/* tsParticles Binary Matrix Background */
#tsBg {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: 1;
}

#tsBg canvas {
  opacity: 0.03;
  transition: opacity var(--transition-slow);
}

#tsBg.is-active canvas {
  opacity: 0.08;
}

/* Animated Background Layers */
.bg-layer {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: -1;
}

/* Starfield Background */
.starfield {
  background: 
    radial-gradient(2px 2px at 20px 30px, var(--neon), transparent),
    radial-gradient(2px 2px at 40px 70px, var(--cyan), transparent),
    radial-gradient(1px 1px at 90px 40px, var(--ink), transparent),
    radial-gradient(1px 1px at 130px 80px, var(--purple), transparent),
    radial-gradient(2px 2px at 160px 30px, var(--neon), transparent);
  background-repeat: repeat;
  background-size: 200px 100px;
  animation: starfield-drift 60s linear infinite;
  opacity: 0.3;
}

@keyframes starfield-drift {
  0% { transform: translateY(0); }
  100% { transform: translateY(-100px); }
}

/* Grid Overlay */
.grid-overlay {
  background-image: 
    linear-gradient(rgba(57, 255, 20, 0.1) 1px, transparent 1px),
    linear-gradient(90deg, rgba(57, 255, 20, 0.1) 1px, transparent 1px);
  background-size: 50px 50px;
  opacity: 0.2;
  animation: grid-pulse 4s ease-in-out infinite alternate;
}

@keyframes grid-pulse {
  0% { opacity: 0.1; }
  100% { opacity: 0.3; }
}

/* Node Network */
.node-network {
  z-index: -1;
}

.network-svg {
  width: 100%;
  height: 100%;
  opacity: 0.6;
}

.node {
  fill: var(--neon);
  filter: drop-shadow(0 0 6px var(--neon));
  animation: node-pulse 3s ease-in-out infinite;
}

.node:nth-child(odd) {
  animation-delay: 1.5s;
}

.connection {
  stroke: var(--neon);
  stroke-width: 1;
  opacity: 0.4;
  stroke-dasharray: 5,5;
  animation: connection-flow 2s linear infinite;
}

@keyframes node-pulse {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

@keyframes connection-flow {
  0% { stroke-dashoffset: 0; }
  100% { stroke-dashoffset: 10; }
}

/* Navigation */
.nav-sticky {
  position: sticky;
  top: 0;
  z-index: 1000;
  background: rgba(10, 10, 10, 0.95);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--ring);
}

.nav-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 var(--space-lg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
}

.nav-logo {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 1.125rem;
}

.logo-icon {
  color: var(--neon);
  filter: drop-shadow(0 0 8px var(--neon));
}

.nav-links {
  display: flex;
  gap: var(--space-xl);
}

.nav-link {
  color: var(--ink-muted);
  text-decoration: none;
  position: relative;
  padding: var(--space-sm) 0;
  transition: var(--transition-normal);
  font-weight: 500;
}

.nav-link:hover,
.nav-link:focus {
  color: var(--neon);
  text-shadow: 0 0 8px var(--neon);
}

.nav-link.active {
  color: var(--neon);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--neon);
  box-shadow: var(--shadow-glow);
  transition: var(--transition-normal);
}

.nav-link:hover::after,
.nav-link:focus::after,
.nav-link.active::after {
  width: 100%;
}

/* Hero Section */
.hero-section {
  padding: var(--space-3xl) 0;
  position: relative;
}

.hero-content {
  text-align: center;
  max-width: 800px;
  margin: 0 auto;
}

.hero-title {
  font-family: var(--font-heading);
  font-size: clamp(2rem, 5vw, 3.5rem);
  font-weight: 900;
  margin-bottom: var(--space-lg);
  background: linear-gradient(135deg, var(--ink) 0%, var(--neon) 100%);
  background-clip: text;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  text-shadow: 0 0 30px var(--neon);
}

.hero-subtitle {
  font-size: 1.25rem;
  color: var(--ink-muted);
  margin-bottom: var(--space-2xl);
  font-weight: 300;
}

/* Status Strip */
.status-strip {
  margin-top: var(--space-2xl);
  overflow-x: auto;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

.status-strip::-webkit-scrollbar {
  display: none;
}

.status-cards {
  display: flex;
  gap: var(--space-lg);
  padding: var(--space-md);
  scroll-snap-type: x mandatory;
  min-width: fit-content;
}

.status-card {
  background: rgba(26, 26, 26, 0.8);
  border: 1px solid var(--ring);
  border-radius: var(--radius-lg);
  padding: var(--space-lg);
  min-width: 140px;
  text-align: center;
  scroll-snap-align: start;
  transition: var(--transition-normal);
  position: relative;
  overflow: hidden;
}

.status-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(57, 255, 20, 0.1), transparent);
  animation: status-scan 3s ease-in-out infinite;
}

.status-card:hover {
  border-color: var(--neon);
  box-shadow: var(--shadow-glow);
  transform: translateY(-2px);
}

.status-value {
  font-family: var(--font-heading);
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--neon);
  margin-bottom: var(--space-xs);
}

.status-label {
  font-size: 0.875rem;
  color: var(--ink-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

@keyframes status-scan {
  0% { left: -100%; }
  50% { left: 100%; }
  100% { left: 100%; }
}

/* Utility Classes */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 var(--space-lg);
}

.card {
  background: rgba(26, 26, 26, 0.8);
  border: 1px solid var(--ring);
  border-radius: var(--radius-xl);
  padding: var(--space-2xl);
  box-shadow: var(--shadow-card);
  backdrop-filter: blur(10px);
  transition: var(--transition-normal);
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--neon), transparent);
  opacity: 0;
  transition: var(--transition-normal);
}

.card:hover::before {
  opacity: 1;
}

.card:hover {
  border-color: var(--neon-dim);
  box-shadow: var(--shadow-lifted), var(--shadow-glow);
  transform: translateY(-4px);
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-md) var(--space-xl);
  border: none;
  border-radius: var(--radius-md);
  font-family: var(--font-primary);
  font-weight: 600;
  font-size: 0.875rem;
  text-decoration: none;
  cursor: pointer;
  transition: var(--transition-normal);
  position: relative;
  overflow: hidden;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.btn::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
  transition: var(--transition-slow);
}

.btn:hover::before {
  left: 100%;
}

.btn--primary {
  background: linear-gradient(135deg, var(--neon-dim), var(--neon-bright));
  color: var(--bg);
  border: 1px solid var(--neon);
  box-shadow: 0 0 20px rgba(57, 255, 20, 0.3);
}

.btn--primary:hover {
  box-shadow: 0 0 30px rgba(57, 255, 20, 0.5);
  transform: translateY(-2px);
}

.btn--primary:active {
  transform: translateY(0);
}

.btn--nav {
  background: transparent;
  color: var(--neon);
  border: 1px solid var(--neon);
}

.btn--nav:hover {
  background: var(--neon);
  color: var(--bg);
  box-shadow: var(--shadow-glow);
}

.btn-icon {
  width: 16px;
  height: 16px;
}

/* Main Content */
.main-content {
  padding: var(--space-3xl) 0;
}

/* Section Styles */
.section-header {
  text-align: center;
  margin-bottom: var(--space-2xl);
}

.section-title {
  font-family: var(--font-heading);
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  font-weight: 700;
  margin-bottom: var(--space-md);
  color: var(--ink);
}

.section-subtitle {
  font-size: 1.125rem;
  color: var(--ink-muted);
  max-width: 600px;
  margin: 0 auto;
}

/* Analyzer Section */
.analyzer-section {
  margin-bottom: var(--space-3xl);
}

.analyzer-card {
  max-width: 800px;
  margin: 0 auto;
}

.input-wrapper {
  margin-bottom: var(--space-xl);
}

.input-label {
  display: block;
  font-weight: 600;
  margin-bottom: var(--space-sm);
  color: var(--ink-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-size: 0.875rem;
}

.flow-input {
  width: 100%;
  padding: var(--space-lg);
  background: rgba(42, 42, 42, 0.5);
  border: 1px solid var(--ring);
  border-radius: var(--radius-lg);
  color: var(--ink);
  font-family: var(--font-primary);
  font-size: 1rem;
  line-height: 1.6;
  resize: vertical;
  min-height: 120px;
  transition: var(--transition-normal);
}

.flow-input::placeholder {
  color: var(--ink-dim);
}

.flow-input:focus {
  outline: none;
  border-color: var(--neon);
  box-shadow: 0 0 0 3px rgba(57, 255, 20, 0.1);
  background: rgba(42, 42, 42, 0.8);
}

.analyzer-actions {
  text-align: center;
}

/* Results Section */
.results-section {
  margin-bottom: var(--space-3xl);
}

.results-card {
  overflow: hidden;
}

.table-wrapper {
  overflow-x: auto;
}

.results-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.875rem;
}

.results-table th,
.results-table td {
  padding: var(--space-lg);
  text-align: left;
  border-bottom: 1px solid var(--ring);
}

.results-table th {
  background: rgba(57, 255, 20, 0.1);
  color: var(--neon);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-size: 0.75rem;
  position: sticky;
  top: 0;
  z-index: 10;
}

.results-table td {
  color: var(--ink-muted);
  transition: var(--transition-fast);
}

.results-table tbody tr:hover td {
  background: rgba(57, 255, 20, 0.05);
  color: var(--ink);
}

/* Security Section */
.security-section {
  margin-bottom: var(--space-3xl);
}

.security-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: var(--space-xl);
  max-width: 1000px;
  margin: 0 auto;
}

.security-card {
  text-align: center;
  padding: var(--space-xl);
}

.security-visual {
  width: 120px;
  height: 120px;
  margin: 0 auto var(--space-lg);
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
}

.security-title {
  font-family: var(--font-heading);
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: var(--space-sm);
  color: var(--ink);
}

.security-desc {
  color: var(--ink-muted);
  font-size: 0.875rem;
}

/* Radar Animation */
.radar-container {
  border: 2px solid var(--neon);
  border-radius: 50%;
  position: relative;
  overflow: hidden;
}

.radar-sweep {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 2px;
  height: 50%;
  background: linear-gradient(to bottom, var(--neon), transparent);
  transform-origin: bottom center;
  transform: translate(-50%, -100%) rotate(0deg);
  animation: radar-sweep 2s linear infinite;
}

.radar-rings {
  position: absolute;
  inset: 10px;
  border-radius: 50%;
}

.radar-ring {
  position: absolute;
  border: 1px solid rgba(57, 255, 20, 0.3);
  border-radius: 50%;
}

.radar-ring:nth-child(1) {
  inset: 0;
}

.radar-ring:nth-child(2) {
  inset: 20px;
}

.radar-ring:nth-child(3) {
  inset: 40px;
}

@keyframes radar-sweep {
  0% { transform: translate(-50%, -100%) rotate(0deg); }
  100% { transform: translate(-50%, -100%) rotate(360deg); }
}

/* Lock Icon */
.lock-container {
  animation: lock-glow 3s ease-in-out infinite;
}

.lock-icon {
  color: var(--neon);
  filter: drop-shadow(0 0 20px var(--neon));
}

@keyframes lock-glow {
  0%, 100% { filter: drop-shadow(0 0 20px var(--neon)); }
  50% { filter: drop-shadow(0 0 40px var(--neon)); }
}

/* Matrix Rain */
.matrix-container {
  background: var(--bg-2);
  border: 1px solid var(--neon);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.matrix-rain {
  display: flex;
  justify-content: space-around;
  height: 100%;
  align-items: center;
}

.matrix-column {
  width: 8px;
  height: 80px;
  background: linear-gradient(to bottom, transparent, var(--neon), transparent);
  animation: matrix-fall 2s linear infinite;
  animation-delay: var(--delay);
}

@keyframes matrix-fall {
  0% { transform: translateY(-100px); opacity: 0; }
  50% { opacity: 1; }
  100% { transform: translateY(100px); opacity: 0; }
}

/* Footer */
.footer {
  background: var(--bg-2);
  border-top: 1px solid var(--ring);
  padding: var(--space-xl) 0;
  margin-top: var(--space-3xl);
}

.footer-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-lg);
}

.footer-brand {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  color: var(--ink-muted);
  font-weight: 600;
}

.footer-logo {
  color: var(--neon);
}

.footer-links {
  display: flex;
  gap: var(--space-xl);
}

.footer-link {
  color: var(--ink-muted);
  text-decoration: none;
  transition: var(--transition-normal);
  font-size: 0.875rem;
}

.footer-link:hover {
  color: var(--neon);
}

/* Responsive Design */
@media (max-width: 768px) {
  .nav-container {
    padding: 0 var(--space-md);
  }

  .nav-links {
    display: none;
  }

  .container {
    padding: 0 var(--space-md);
  }

  .status-cards {
    padding: var(--space-md) 0;
  }

  .security-grid {
    grid-template-columns: 1fr;
    gap: var(--space-lg);
  }

  .footer-content {
    flex-direction: column;
    text-align: center;
  }

  .footer-links {
    justify-content: center;
  }

  /* tsParticles Mobile Adjustments - Remove mobile aura styles */
}

@media (max-width: 480px) {
  .hero-section {
    padding: var(--space-xl) 0;
  }

  .main-content {
    padding: var(--space-xl) 0;
  }

  .card {
    padding: var(--space-lg);
  }

  .results-table th,
  .results-table td {
    padding: var(--space-sm);
  }
}

/* Accessibility */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .bg-layer {
    display: none;
  }

  /* tsParticles Reduced Motion */
  #tsBg canvas {
    opacity: 0.02 !important;
  }

  #tsBg.is-active canvas {
    opacity: 0.02 !important;
  }
}

/* Focus Styles */
*:focus {
  outline: 2px solid var(--neon);
  outline-offset: 2px;
}

.btn:focus,
.nav-link:focus,
.flow-input:focus {
  outline: 2px solid var(--neon);
  outline-offset: 2px;
}

/* High Contrast Mode */
@media (prefers-contrast: high) {
  :root {
    --bg: #000000;
    --bg-2: #111111;
    --ink: #ffffff;
    --neon: #00ff00;
    --ring: #666666;
  }
}

/* Print Styles */
@media print {
  .bg-layer,
  .nav-sticky,
  .status-strip,
  .security-section,
  .footer {
    display: none;
  }

  body {
    background: white;
    color: black;
  }

  .card {
    border: 1px solid black;
    box-shadow: none;
  }
}

